const body = $json.body || $json;
const payload = body.payload || body;
const cycle = payload.cycle || payload;
const stage = cycle.stage || payload.kind || 'audit';
let route = 'odessa-geral';
if (stage === 'erro' || payload.kind === 'error') route = 'odessa-qa';
if (payload.kind === 'decision') route = 'odessa-decisoes';
if (payload.kind === 'autopilot_cycle') route = 'odessa-dev-log';
const actions = Array.isArray(cycle.actions) ? cycle.actions.map((action) => ({ capability: action.capability, status: action.status, result: action.result })) : [];
return [{ json: { route, stage, slackChannel: `#${route}`, text: `Odessa audit: ${stage}`, summary: { id: cycle.id, intent: cycle.decision?.intent, confidence: cycle.decision?.confidence, actions, createdAt: body.createdAt || new Date().toISOString() } } }];
